3122	\begin{lemma}[Sheaf Mayer--Vietoris: the pullback cone over a two-open cover is a limit]
3123	  \label{lem:isLimitPullbackCone_mathlib}
3124	  \lean{TopCat.Sheaf.isLimitPullbackCone}
3125	  \mathlibok
3126	  \textit{Provided by Mathlib
3127	  (\texttt{Mathlib.Topology.Sheaves.SheafCondition.PairwiseIntersections}).}
3128	  For a sheaf \(F\) on a topological space and two opens \(U, V\), the square relating
3129	  \(F(U \cup V)\), \(F(U)\), \(F(V)\), \(F(U \cap V)\) is a pullback (limit). This is the generic
3130	  module Mayer--Vietoris used in the inductive step of the descent.
3131	\end{lemma}
