3149	\begin{lemma}[Separatedness: a section is determined by its restrictions to a cover]
3150	  \label{lem:eq_of_locally_eq_mathlib}
3151	  \lean{TopCat.Sheaf.eq_of_locally_eq'}
3152	  \mathlibok
3153	  \textit{Provided by Mathlib
3154	  (\texttt{Mathlib.Topology.Sheaves.SheafCondition.UniqueGluing}).}
3155	  Let \(F\) be a sheaf on a topological space, \(V\) an open, and \(\{U_i\}\) a family of opens with
3156	  \(\bigsqcup_i U_i = V\). If two sections \(s, t \in F(V)\) have equal restrictions
3157	  \(s|_{U_i} = t|_{U_i}\) for every \(i\), then \(s = t\). This separatedness over a cover is the
3158	  uniqueness half of the sheaf condition; it discharges the \(\mathrm{exists\_of\_eq}\) obligation
3159	  (a global section vanishing on \(D(f)\) is killed by a power of \(f\)) and the final
3160	  ``conclude on \(D(f)\)'' step of the cover-form descent
3161	  (\cref{lem:section_localization_descent_of_cover}).
3162	\end{lemma}
